import{c as t,Q as o,j as a,m as s}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Roles & Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/roles-and-permissions.md","filePath":"guide/concepts/roles-and-permissions.md","lastUpdated":1778862269000}'),n={name:"guide/concepts/roles-and-permissions.md"};function r(i,e,c,d,l,h){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="roles-permissions" tabindex="-1">Roles &amp; Permissions <a class="header-anchor" href="#roles-permissions" aria-label="Permalink to &quot;Roles &amp; Permissions&quot;">​</a></h1><p>Two role systems coexist in the Console: <strong>internal roles</strong> (for Exto operators) and <strong>portal roles</strong> (for customer users). They are intentionally separate. An internal operator never has a portal role; a customer admin never has an internal role.</p><h2 id="internal-roles" tabindex="-1">Internal roles <a class="header-anchor" href="#internal-roles" aria-label="Permalink to &quot;Internal roles&quot;">​</a></h2><p>Internal roles control what an Exto operator can do across the platform. A user can hold more than one role.</p><table tabindex="0"><thead><tr><th>Role</th><th>What they can do</th></tr></thead><tbody><tr><td><strong>Platform Admin</strong></td><td>Full access. Manages instances, plans, internal users, system pages, and platform configuration.</td></tr><tr><td><strong>Infra Ops</strong></td><td>Operates the fleet — instances, releases, migrations, environment variables, system workers, discrepancies.</td></tr><tr><td><strong>Account Manager</strong></td><td>Manages a defined set of customers — onboarding, plan changes, billing, invitations. Restricted to their <strong>customer scope</strong>.</td></tr><tr><td><strong>QA Admin</strong></td><td>Operates against a defined set of customers <em>and</em> a defined set of instances — typically used to run QA cycles or validation against specific non-prod environments. Restricted to both <strong>customer scope</strong> and <strong>instance scope</strong>.</td></tr></tbody></table><p>When you create an internal user with the Account Manager or QA Admin role, a <strong>scope picker</strong> appears so you can grant the customers (and, for QA Admin, the instances) they may operate on. Empty scope means no access; you must grant at least one entry for the user to be useful.</p><p>Scopes can be modified at any time on the user&#39;s detail page.</p><h2 id="portal-roles" tabindex="-1">Portal roles <a class="header-anchor" href="#portal-roles" aria-label="Permalink to &quot;Portal roles&quot;">​</a></h2><p>Portal roles control what a customer&#39;s users can do inside their customer&#39;s portal.</p><table tabindex="0"><thead><tr><th>Role</th><th>What they can do</th></tr></thead><tbody><tr><td><strong>Owner</strong></td><td>Full control of the customer. Manages tenants, users, billing, and settings.</td></tr><tr><td><strong>Admin</strong></td><td>Manages tenants, users, and (depending on settings configuration) some of the customer&#39;s configuration.</td></tr><tr><td><strong>Member</strong></td><td>Limited access — typically used for tenant-scoped users who do not need to manage the customer overall.</td></tr></tbody></table><p>Beyond a user&#39;s portal role, there is also <strong>tenant assignment</strong>: which tenants the user has been provisioned into, and the role they hold <em>inside</em> each tenant (e.g. Tenant Admin vs. Tenant User). A user can be a customer Admin but only a Tenant User on a particular tenant, or vice versa.</p><h2 id="portal-actions" tabindex="-1">Portal actions <a class="header-anchor" href="#portal-actions" aria-label="Permalink to &quot;Portal actions&quot;">​</a></h2><p>Underneath portal roles, individual pages and buttons are gated by <strong>portal actions</strong> such as <code>view_dashboard</code>, <code>view_tenants</code>, <code>manage_tenant_users</code>, <code>view_billing</code>, <code>manage_settings</code>, <code>view_changelog</code>. When the UI hides a button or page, the missing action is the reason.</p><p>The mapping of role → actions is part of the customer&#39;s authorisation configuration.</p><h2 id="account-manager-scope" tabindex="-1">Account Manager scope <a class="header-anchor" href="#account-manager-scope" aria-label="Permalink to &quot;Account Manager scope&quot;">​</a></h2><p>Account Managers see only the customers in their scope. If an AM has scope <code>{Acme, Globex}</code>, they cannot list, open, or operate on any other customer — those rows simply do not appear. This is <strong>scope hiding</strong>, not just access denial: the AM never sees data outside their scope.</p><h2 id="qa-admin-scope" tabindex="-1">QA Admin scope <a class="header-anchor" href="#qa-admin-scope" aria-label="Permalink to &quot;QA Admin scope&quot;">​</a></h2><p>QA Admins are doubly scoped:</p><ul><li>The <strong>customer scope</strong> decides which customers they may operate on.</li><li>The <strong>instance scope</strong> decides which instances they may act against.</li></ul><p>QA Admins are typically used to run validation flows against specific non-prod customers and instances without granting broad access.</p><h2 id="notifications" tabindex="-1">Notifications <a class="header-anchor" href="#notifications" aria-label="Permalink to &quot;Notifications&quot;">​</a></h2><p>A separate layer of subscriptions controls what notifications users receive (in-app and email). Notifications are grouped by category (Operations, Discrepancies, Billing, Infrastructure, General). Some subscriptions are marked <strong>Required</strong> — they are mandatory for the user&#39;s role and cannot be turned off.</p><p>Users manage their own subscriptions on the <strong>Account</strong> page. Operators viewing another user&#39;s detail page see subscriptions read-only.</p><h2 id="focus-mode" tabindex="-1">Focus mode <a class="header-anchor" href="#focus-mode" aria-label="Permalink to &quot;Focus mode&quot;">​</a></h2><p>Operators with broad access can enter <strong>focus mode</strong> on a single customer. While focused, the Dashboard and other aggregate views hide cross-customer information and present only the focused customer&#39;s data. Focus mode is a viewing convenience — it does not change what the operator is permitted to do.</p>',25)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
